const body = $input.first().json.body || $input.first().json;
const event = body.event || body;
const data = body.data || {};
const issue = data.issue || data;

// Extract fields with full fallback chain including body-level fields
const title = issue.title || event.title || data.title || body.title || 'Unknown Error';
const culprit = issue.culprit || event.culprit || data.culprit || body.culprit || '';
const message = issue.message || event.message || data.message || body.message || '';
const level = issue.level || event.level || data.level || body.level || 'error';
const project = issue.project?.name || body.project_name || body.project || 'homelab';
const url = issue.url || data.url || event.url || body.url || '';
const eventId = issue.id || event.event_id || event.id || body.event_id || '';
const shortId = issue.shortId || issue.short_id || body.short_id || '';

// Skip if title extraction still failed — prevents noise issues
if (title === 'Unknown Error') {
  console.log('[GlitchTip] Skipping event with unresolvable title. Raw keys: ' + Object.keys(body).join(', '));
  return [];
}

// Generate fingerprint hash for deduplication
let hash = 0;
const fingerprint = title + ':' + culprit;
for (let i = 0; i < fingerprint.length; i++) {
  const char = fingerprint.charCodeAt(i);
  hash = ((hash << 5) - hash) + char;
  hash |= 0;
}
const fingerprintHash = Math.abs(hash).toString(16).padStart(8, '0').slice(0, 8);

return [{
  json: {
    title, culprit, message, level, project, url, eventId, shortId,
    fingerprint: fingerprintHash
  }
}];

// Rate limiter: max 10 issues per 5-minute window
const MAX_ISSUES = 10;
const WINDOW_MS = 5 * 60 * 1000;

const now = Date.now();
const staticData = $getWorkflowStaticData('global');

if (!staticData.rateLimitEntries) {
  staticData.rateLimitEntries = [];
}
staticData.rateLimitEntries = staticData.rateLimitEntries.filter(ts => now - ts < WINDOW_MS);

const isRateLimited = staticData.rateLimitEntries.length >= MAX_ISSUES;

if (!isRateLimited) {
  staticData.rateLimitEntries.push(now);
}

return [{
  json: {
    ...$input.first().json,
    isRateLimited,
    rateLimitCount: staticData.rateLimitEntries.length,
    rateLimitMax: MAX_ISSUES
  }
}];

// SYNC: This classification logic is duplicated in alert-to-github-issue.json
const SERVICE_MAP = {
  'mcphub': 'svc:mcphub', 'mcp': 'svc:mcphub',
  'grafana': 'svc:grafana', 'prometheus': 'svc:grafana',
  'elk': 'svc:elk', 'elasticsearch': 'svc:elk', 'logstash': 'svc:elk', 'kibana': 'svc:elk',
  'glitchtip': 'svc:glitchtip',
  'traefik': 'svc:traefik', 'proxy': 'svc:traefik', 'gateway': 'svc:traefik',
  'n8n': 'svc:n8n', 'blacklist': 'svc:blacklist',
  'proxmox': 'svc:proxmox', 'ceph': 'svc:proxmox', 'pve': 'svc:proxmox'
};
const HOST_MAP = {
  'pve': 'host:pve', 'pve3': 'host:pve', 'mcphub': 'host:mcphub',
  'grafana': 'host:grafana', 'elk': 'host:elk', 'traefik': 'host:traefik',
  'glitchtip': 'host:glitchtip', 'oc': 'host:oc', 'jclee-dev': 'host:oc',
  'sandbox': 'host:sandbox', 'ubuntu': 'host:sandbox', 'runner': 'host:runner'
};
const SEVERITY_MAP = {
  'critical': 'P0-critical', 'fatal': 'P0-critical',
  'error': 'P1-high', 'warning': 'P2-medium', 'warn': 'P2-medium',
  'info': 'P3-low', 'debug': 'P3-low'
};

const prev = $input.first().json;
const searchText = (prev.title + ' ' + prev.culprit + ' ' + prev.project).toLowerCase();

let serviceLabel = '';
for (const [kw, label] of Object.entries(SERVICE_MAP)) {
  if (searchText.includes(kw)) { serviceLabel = label; break; }
}
let hostLabel = '';
for (const [kw, label] of Object.entries(HOST_MAP)) {
  if (searchText.includes(kw)) { hostLabel = label; break; }
}
const priorityLabel = SEVERITY_MAP[prev.level?.toLowerCase()] || 'P1-high';
const targetRepo = serviceLabel === 'svc:blacklist' ? 'qws941/blacklist' : 'qws941/proxmox';
const labels = ['bug', 'glitchtip', 'automated', priorityLabel];
if (serviceLabel) labels.push(serviceLabel);
if (hostLabel) labels.push(hostLabel);

return [{ json: { ...prev, classifiedLabels: labels, targetRepo, priorityLabel, serviceLabel, hostLabel } }];

const classified = $('Classify Error').first().json;
const searchResult = $input.first().json;
const issueTitle = '[GlitchTip] ' + classified.title + ' [' + classified.fingerprint + ']';

let isDuplicate = false;
let existingIssueNumber = null;

if (searchResult.total_count > 0 && searchResult.items?.length > 0) {
  isDuplicate = true;
  existingIssueNumber = searchResult.items[0].number;
}

return [{ json: { ...classified, isDuplicate, existingIssueNumber, issueTitle } }];

const classified = $('Check Duplicate').first().json;
const milestones = $input.first().json;

const now = new Date();
const yearStart = new Date(now.getFullYear(), 0, 1);
const weekNum = Math.ceil(((now - yearStart) / 86400000 + yearStart.getDay() + 1) / 7);
const weekStr = 'Week ' + now.getFullYear() + '-W' + String(weekNum).padStart(2, '0');

let milestoneNumber = null;
if (Array.isArray(milestones)) {
  const match = milestones.find(m => m.title && m.title.includes(weekStr));
  if (match) milestoneNumber = match.number;
}

return [{ json: { ...classified, milestoneNumber, weekStr } }];

// Log rate-limited errors for observability
const data = $input.first().json;
console.log(`[Rate Limited] Dropping error: ${data.title || 'unknown'} (${data.rateLimitCount}/${data.rateLimitMax} in window)`);
return [{ json: { ...data, dropped: true, reason: 'rate_limited' } }];
